/* 声明变量 */
if (typeof currentLocation === 'undefined') var currentLocation = getvar('stat_data.世界.当前地点', { defaults: '' });
if (typeof level === 'undefined') var level = getvar('stat_data.主角.属性.等级', { defaults: 0 });
if (typeof groupConnections === 'undefined') var groupConnections = getvar('stat_data.主角.人脉.团体', { defaults: {} });

/* 辅助函数：检查单个团体是否满足条件 (存在且关系度>3) */
/* 注意：为了代码简洁，直接在if中展开判断 */
_%>

<%_
/* 逻辑判断部分 */
/* 条件1：位于神魔智学园 */
var isAtSchool = currentLocation.includes('神魔智学园');

/* 条件2：等级 >= 4 */
var isLevelEnough = (level >= 4);

/* 条件3：特定团体人脉关系度 > 3 */
/* 检查：悦乐同盟、炼狱斗技场、伊什塔尔神殿、大江山酒窖、克洛塞尔大浴场、神魔智学园 */
var hasConnection = false;

if (typeof groupConnections['悦乐同盟'] !== 'undefined' && groupConnections['悦乐同盟'].关系度 > 3) hasConnection = true;
if (typeof groupConnections['炼狱斗技场'] !== 'undefined' && groupConnections['炼狱斗技场'].关系度 > 3) hasConnection = true;
if (typeof groupConnections['伊什塔尔神殿'] !== 'undefined' && groupConnections['伊什塔尔神殿'].关系度 > 3) hasConnection = true;
if (typeof groupConnections['大江山酒窖'] !== 'undefined' && groupConnections['大江山酒窖'].关系度 > 3) hasConnection = true;
if (typeof groupConnections['克洛塞尔大浴场'] !== 'undefined' && groupConnections['克洛塞尔大浴场'].关系度 > 3) hasConnection = true;
if (typeof groupConnections['神魔智学园'] !== 'undefined' && groupConnections['神魔智学园'].关系度 > 3) hasConnection = true;
_%>

<%_ /* 最终判定：位于学园 AND (等级够 OR 有人脉) */ _%>
<%_ if (isAtSchool && (isLevelEnough || hasConnection)) { _%>
