42.content:
@@preprocessing
<%_
if (typeof clueCache === 'undefined') var clueCache = getvar('stat_data.剧本系统.待发线索缓存', { defaults: {} });
if (typeof currentScript === 'undefined') var currentScript = getvar('stat_data.剧本系统.当前剧本', { defaults: '' });
if (typeof hasClueM === 'undefined') var hasClueM = false;
if (typeof hasClueO === 'undefined') var hasClueO = false;

// 安全遍历缓存对象，精确查找线索ID
for (var key in clueCache) {
    if (clueCache[key] && clueCache[key].id === 'M') {
        hasClueM = true;
    }
    if (clueCache[key] && clueCache[key].id === 'O') {
        hasClueO = true;
    }
}
_%>

<%_ if (currentScript === 'CROSS GAME' && hasClueM) { _%>
●特殊遭遇：头目出面
    - 仅限星期日12~21点期间，主角处于神魔智街时，可触发。通常来说，该遭遇仅会发生一次。酒吞童子、Algolagnia、帕凡娜中的一人将会亲自出面，并上前与PC搭话。他们对当前情况感到不满，和久远寺正己一样希望能够尽快解决问题。
    - 此时进行业力判定(交涉)。若成功，则实力会被对方认可。如果能阻止下一次谋杀并打倒凶手，对方会许诺支付[判定值×10]的信用点作为额外报酬。
<%_ } _%>

<%_ if (currentScript === 'CROSS GAME' && hasClueO) { _%>
●特殊遭遇：追猎者的争斗
    - 两名追猎者（战斗数据套用「兼职追猎者」）正在因争夺情报源而陷入剑拔弩张的局面。而且，双方会将主角视为新的敌人，并联手发起攻击。
    - 战斗后，主角可进行业力判定(察觉)。若成功，将会察觉到正在监视这一切的追猎者。可以触发特殊遭遇「追踪追猎者」。
<%_ } _%>
